const SUPPORTED = new Set(['en','fr','de','es','it','pt','nl','pl','ro','el','cs','hu','sv','bg','da','fi','sk','hr','lt','sl','lv','et','ga','mt']);

function detectLang() {
  const nav = (navigator.language || '').substring(0, 2).toLowerCase();
  return SUPPORTED.has(nav) ? nav : 'en';
}

